  "confidence_score": 0.98,
  "attack_summary": "An attacker utilized the legitimate `ntdsutil.exe` utility with the 'ifm create full' command to dump the Active Directory database (NTDS.dit) and associated registry hives. This activity, with output directed to a suspicious temporary directory (`C:\\Windows\\Temp`), is a well-known technique for offline credential extraction. The successful creation of these critical files indicates a significant compromise aimed at gaining Active Directory credentials.",
  "malicious_processes": [
    "P[ntdsutil.exe|{fe86be69-095]"
  ],
  "kill_chain_stages": [
    "Credential Access",
    "Collection"
  ],
  "techniques": [
    {
      "tactic": "Credential Access",
      "tid": "T1003.003",
      "evidence": "The process P[ntdsutil.exe|{fe86be69-095] was executed with the 'ifm create full' command, leading to the creation of 'ntds.dit', 'SYSTEM', and 'SECURITY' files in 'C:\\Windows\\Temp'."
    },
    {
      "tactic": "Collection",
      "tid": "T1005",
      "evidence": "The Active Directory database ('ntds.dit') and system registry hives were collected and written to 'C:\\Windows\\Temp\\ntds_T1003\\Active Directory' and 'C:\\Windows\\Temp\\ntds_T1003\\registry' respectively."
    }
  ]
}
